            <button
              key={tab.key}
              type="button"
              data-cid={`project-detail-tab-${tab.key}-site-section`}
              onClick={() => setTab(tab.key)}
              className={cn(
                "px-3 py-2 text-xs font-medium transition-colors",
                activeTab === tab.key
                  ? "border-b-2 border-accent text-accent"
