        version it was observed under, so comparisons across versions stay honest.
      </p>

      <div className="mt-8 space-y-6">
        {findings.map((f) => (
          <ProjectFindingArticle key={f.slug} finding={f} />
        ))}
      </div>
      </Identified>
    </SiteSection>
  );
}

