function renderListTable(rows) {
  // Columns per byok-design §7.3: KEY VERSION PROVIDER SCOPE LAST ROTATED
  const headers = ['KEY', 'VERSION', 'PROVIDER', 'SCOPE', 'LAST ROTATED'];
  const data = rows.map((r) => [
