"use client";

import { useMemo, useState } from "react";
import type { PlanningNote } from "@/lib/planning-data";

interface NotesTabProps {
  notes: PlanningNote[];
}

export function NotesTab({ notes }: NotesTabProps) {
  const [query, setQuery] = useState("");
  const filtered = useMemo(() => {
    if (!query.trim()) return notes;
    const q = query.trim().toLowerCase();
    return notes.filter((n) =>
      `${n.title} ${n.snippet} ${n.relPath}`.toLowerCase().includes(q),
    );
  }, [notes, query]);

  if (notes.length === 0) {
    return (
      <div
        data-cid="planning-notes-tab"
        className="rounded-md border border-dashed border-border/50 bg-muted/10 px-4 py-6 text-center text-xs text-muted-foreground"
      >
        No .planning notes/docs found.
      </div>
    );
  }

  return (
    <div data-cid="planning-notes-tab" className="space-y-3">
      <div className="flex items-center gap-3">
        <span className="text-sm text-muted-foreground">
          <strong className="text-foreground">{notes.length}</strong> notes
        </span>
        <input
          type="search"
          placeholder="Filter…"
          value={query}
          onChange={(e) => setQuery(e.target.value)}
          className="ml-auto rounded border border-border bg-card px-2 py-1 text-xs text-foreground placeholder:text-muted-foreground focus:border-accent focus:outline-none"
        />
      </div>
      {filtered.map((n) => (
        <article
          key={n.id}
          className="rounded-md border border-border/60 bg-muted/10 p-3"
        >
          <div className="flex flex-wrap items-center justify-between gap-2">
            <h3 className="text-sm font-semibold text-foreground">{n.title}</h3>
            <time className="text-xs tabular-nums text-muted-foreground">
              {new Date(n.updatedAt).toLocaleDateString()}
            </time>
          </div>
          <p className="mt-1 text-xs leading-5 text-muted-foreground">
            {n.snippet || "No preview."}
          </p>
          <details className="mt-2">
            <summary className="cursor-pointer text-xs text-foreground/80">
              Path
            </summary>
            <p className="mt-1 font-mono text-[11px] text-muted-foreground">
              .planning/{n.relPath}
            </p>
          </details>
        </article>
      ))}
      {filtered.length === 0 && (
        <div className="rounded-md border border-dashed border-border/50 bg-muted/10 px-4 py-6 text-center text-xs text-muted-foreground">
          No matches.
        </div>
      )}
    </div>
  );
}

