function safeCall<T>(fn: () => T, fallback: T): T {
  try {
    return fn();
  } catch {
    return fallback;
  }
}

export function loadPlanningData(
  projectId: string = "get-anything-done",
): ProjectPlanningData | null {
  const baseDir = resolveProjectBaseDir(projectId);
  if (!baseDir) return null;

  const readers = getReaders();
  const root = { id: projectId, path: ".", planningDir: ".planning" };

  const tasks = safeCall(() => readers.readTasks(root, baseDir), []);
  const decisions = safeCall(() => readers.readDecisions(root, baseDir), []);
  const phases = safeCall(() => readers.readPhases(root, baseDir), []);
  const requirements = safeCall(
    () => readers.readRequirements(root, baseDir),
    [],
  );
  const stateRaw = safeCall<PlanningState | PlanningState[] | null>(
    () => readers.readState(root, baseDir),
    null,
  );
  const state = Array.isArray(stateRaw)
    ? (stateRaw[0] ?? null)
    : (stateRaw ?? null);

  const planningDirAbs = path.join(baseDir, ".planning");
  const notes = collectNotes(planningDirAbs);

  return {
    projectId,
    tasks,
    decisions,
    phases,
    requirements,
    notes,
    state,
  };
}
