import * as fs from "node:fs";

// Hide the CJS loader from webpack/Turbopack static analysis. Next's
// Server-Components webpack layer wraps this file in an ESM closure where
// `require` is not defined, and it rewrites `createRequire(expr)` into a
// stub when the expression is a file path. Both paths break the canonical
// `import { createRequire } from "node:module"` idiom.
//
// Workaround: resolve the CJS loader via `process.getBuiltinModule`, which
// is a Node 22+ runtime hook that is opaque to the bundler.
// eslint-disable-next-line @typescript-eslint/no-explicit-any
const proc = process as unknown as {
  getBuiltinModule?: (id: string) => { createRequire: (from: string) => NodeJS.Require };
};
const nodeModule = proc.getBuiltinModule
  ? proc.getBuiltinModule("node:module")
  : null;
if (!nodeModule) {
  throw new Error(
    "planning-data: process.getBuiltinModule not available — requires Node 22+",
  );
}
const _createRequire = nodeModule.createRequire;

